import { execFile } from "node:child_process";
import { access } from "node:fs/promises";
import { promisify } from "node:util";
import { AGENT_REGISTRY } from "../config/agents.ts";
import type { AgentConfig, AgentId } from "../types.ts";
import { resolveAgentDetectPath } from "./resolve.ts";

const execFileAsync = promisify(execFile);

// Injectable executor for testing: receives a command and its arguments and
// must throw on non-zero exit (same contract as the promisified execFile).
export type ExecFn = (cmd: string, args: readonly string[]) => Promise<void>;

const defaultExecFn: ExecFn = async (cmd, args) => {
  await execFileAsync(cmd, args as string[]);
};

export async function detectInstalledAgents(home: string): Promise<AgentId[]> {
  const detected: AgentId[] = [];

  for (const agent of AGENT_REGISTRY) {
    if (await isAgentInstalled(agent, home)) {
      detected.push(agent.id);
    }
  }

  return detected;
}

async function isAgentInstalled(
  agent: AgentConfig,
  home: string,
): Promise<boolean> {
  const detectPath = resolveAgentDetectPath(agent, home);
  try {
    await access(detectPath);
    return true;
  } catch {
    // path does not exist — fall through to binary detection
  }

  if (agent.detectBinary) {
    return isBinaryInPath(agent.detectBinary);
  }

  return false;
}

export async function isBinaryInPath(
  binary: string,
  execFn: ExecFn = defaultExecFn,
  platform: NodeJS.Platform = process.platform,
): Promise<boolean> {
  if (platform === "win32") {
    return isBinaryViaWhereExe(binary, execFn);
  }

  try {
    await execFn("which", [binary]);
    return true;
  } catch (err: unknown) {
    // `which` itself is not installed — fall back to the POSIX shell built-in
    if (isENOENT(err)) {
      return isBinaryViaCommandV(binary, execFn);
    }
    return false;
  }
}

// Windows-only: use where.exe to check if a binary is in PATH.
export async function isBinaryViaWhereExe(
  binary: string,
  execFn: ExecFn = defaultExecFn,
): Promise<boolean> {
  try {
    await execFn("where.exe", [binary]);
    return true;
  } catch {
    return false;
  }
}

// Used only when `which` is absent (e.g. minimal Alpine containers).
// `command -v` is a POSIX shell built-in available wherever /bin/sh is.
export async function isBinaryViaCommandV(
  binary: string,
  execFn: ExecFn = defaultExecFn,
): Promise<boolean> {
  try {
    // Pass binary as a positional arg ($1) to avoid any shell-injection risk.
    await execFn("sh", ["-c", 'command -v "$1"', "--", binary]);
    return true;
  } catch {
    return false;
  }
}

// POSIX: use `which` to check if a binary is in PATH.
export async function isBinaryViaWhich(
  binary: string,
  execFn: ExecFn = defaultExecFn,
): Promise<boolean> {
  try {
    await execFn("which", [binary]);
    return true;
  } catch {
    return false;
  }
}

function isENOENT(err: unknown): boolean {
  return (
    typeof err === "object" &&
    err !== null &&
    (err as NodeJS.ErrnoException).code === "ENOENT"
  );
}

import { constants } from "node:fs";
import {
  access,
  copyFile,
  cp,
  lstat,
  mkdir,
  readFile,
  realpath,
  rename,
  rm,
  symlink,
  unlink,
  writeFile,
} from "node:fs/promises";
import path from "node:path";
import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import { UserError } from "../errors.ts";
import { logger } from "../logger.ts";
import type {
  AgentId,
  ConfigPatchDeployAction,
  DeployAction,
  FileWriteDeployAction,
  Manifest,
  PlannedChange,
  PlanWarning,
  SkillDirDeployAction,
} from "../types.ts";
import { compileAdapterActions } from "./adapters/index.ts";
import {
  lookupDeployment,
  type RegistryPersistence,
  registerDeployment,
  verifyDeployment,
} from "./ownership.ts";
import { getDeployMethod, resolveAgentSkillPath } from "./resolve.ts";
import { resolveTargetTemplate } from "./runtime-paths.ts";
import {
  sourceAccessError,
  validateSkillDefinitionFile,
  validateSourceFile,
  validateSourcePath,
} from "./validation.ts";

function isPlainObject(v: unknown): v is Record<string, unknown> {
  return typeof v === "object" && v !== null && !Array.isArray(v);
}

async function readJsonConfigFile(
  filePath: string,
): Promise<Record<string, unknown>> {
  let rawContent: string;
  try {
    rawContent = await readFile(filePath, "utf-8");
  } catch (err) {
    const code = (err as NodeJS.ErrnoException).code;
    if (code === "ENOENT")
      throw new Error(`Config file not found: ${filePath}`);
    throw err;
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(rawContent);
  } catch {
    throw new Error(`Config file is not valid JSON: ${filePath}`);
  }

  if (!isPlainObject(parsed)) {
    throw new Error(`Config file is not a JSON object: ${filePath}`);
  }

  return parsed;
}

function computeUndoPatch(
  original: Record<string, unknown>,
  patch: Record<string, unknown>,
): Record<string, unknown> {
  const undoPatch: Record<string, unknown> = {};
  for (const key of Object.keys(patch)) {
    const patchVal = patch[key];
    if (isPlainObject(patchVal) && isPlainObject(original[key])) {
      undoPatch[key] = computeUndoPatch(
        original[key] as Record<string, unknown>,
        patchVal as Record<string, unknown>,
      );
    } else {
      undoPatch[key] = key in original ? original[key] : null;
    }
  }
  return undoPatch;
}

function applyMergePatch(
  original: Record<string, unknown>,
  patch: Record<string, unknown>,
): Record<string, unknown> {
  const patched: Record<string, unknown> = { ...original };
  for (const [key, value] of Object.entries(patch)) {
    if (value === null) {
      delete patched[key];
    } else if (isPlainObject(value) && isPlainObject(patched[key])) {
      patched[key] = applyMergePatch(
        patched[key] as Record<string, unknown>,
        value as Record<string, unknown>,
      );
    } else {
      patched[key] = value;
    }
  }
  return patched;
}

function detectCollisions(actions: DeployAction[]): PlanWarning[] {
  const seen = new Map<string, { skill: string; agent: AgentId }>();
  const warnings: PlanWarning[] = [];
  for (const action of actions) {
    const prev = seen.get(action.target);
    if (prev) {
      warnings.push({
        kind: "collision",
        message: `Skill "${action.skill}" for agent "${action.agent}" and skill "${prev.skill}" for agent "${prev.agent}" both resolve to the same target: ${action.target}`,
      });
    } else {
      seen.set(action.target, { skill: action.skill, agent: action.agent });
    }
  }
  return warnings;
}

function detectAmbiguities(
  detectedAgents: AgentId[],
  manifest: Manifest,
): PlanWarning[] {
  const warnings: PlanWarning[] = [];

  if (
    !(
      detectedAgents.includes("gemini-cli") &&
      detectedAgents.includes("antigravity")
    )
  ) {
    return warnings;
  }

  const bothAgents = (agents: AgentId[]) =>
    agents.includes("gemini-cli") && agents.includes("antigravity");

  for (const entry of manifest.agentRules ?? []) {
    if (bothAgents(entry.agents)) {
      warnings.push({
        kind: "ambiguity",
        message: `Both "gemini-cli" and "antigravity" are listed in agentRules entry "${entry.name}". They share a GEMINI.md-backed instruction shared surface — verify that deploying to both does not create conflicting behavior.`,
      });
    }
  }

  for (const entry of manifest.mcpServers ?? []) {
    if (bothAgents(entry.agents)) {
      warnings.push({
        kind: "ambiguity",
        message: `Both "gemini-cli" and "antigravity" are listed in mcpServers entry "${entry.name}". "gemini-cli" writes to ~/.gemini/settings.json as a shared surface — verify that deploying to both does not produce conflicting MCP server behavior.`,
      });
    }
  }

  return warnings;
}

async function planSkillDirActions(
  manifest: Manifest,
  sourceDir: string,
  resolvedSourceDir: string,
  realRoot: string,
  detectedAgents: AgentId[],
  home: string,
): Promise<SkillDirDeployAction[]> {
  const method = getDeployMethod();
  const actions: SkillDirDeployAction[] = [];
  for (const skill of manifest.skills) {
    const targetAgents = skill.agents.filter((agentId) =>
      detectedAgents.includes(agentId),
    );
    if (targetAgents.length === 0) continue;

    const source = path.resolve(sourceDir, skill.path);
    await validateSourcePath(source, skill.path, resolvedSourceDir, realRoot);
    await validateSkillContract(source, skill.path);
    for (const agentId of targetAgents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        source,
        target: resolveAgentSkillPath(agent, skill.name, home),
        method,
        confidence: agent.provenance.skills,
      });
    }
  }
  return actions;
}

async function planFileWriteActions(
  manifest: Manifest,
  sourceDir: string,
  resolvedSourceDir: string,
  realRoot: string,
  detectedAgents: AgentId[],
  home: string,
): Promise<FileWriteDeployAction[]> {
  const actions: FileWriteDeployAction[] = [];
  for (const fileEntry of manifest.files ?? []) {
    const targetAgents = fileEntry.agents.filter((agentId) =>
      detectedAgents.includes(agentId),
    );
    if (targetAgents.length === 0) continue;

    const source = path.resolve(sourceDir, fileEntry.path);
    await validateSourcePath(
      source,
      fileEntry.path,
      resolvedSourceDir,
      realRoot,
    );
    await validateSourceFile(source, fileEntry.path);
    for (const agentId of targetAgents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;
      actions.push({
        kind: "file-write",
        skill: fileEntry.name,
        agent: agentId,
        source,
        target: resolveTargetTemplate(fileEntry.target, home),
        confidence: agent.provenance.skills,
      });
    }
  }
  return actions;
}

function planConfigPatchActions(
  manifest: Manifest,
  detectedAgents: AgentId[],
  home: string,
): ConfigPatchDeployAction[] {
  const actions: ConfigPatchDeployAction[] = [];
  for (const configEntry of manifest.configs ?? []) {
    for (const agentId of configEntry.agents) {
      if (!detectedAgents.includes(agentId)) continue;
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;
      actions.push({
        kind: "config-patch",
        skill: configEntry.name,
        agent: agentId,
        target: resolveTargetTemplate(configEntry.target, home),
        patch: configEntry.patch,
        confidence: agent.provenance.skills,
      });
    }
  }
  return actions;
}

export async function planDeploy(
  manifest: Manifest,
  sourceDir: string,
  detectedAgents: AgentId[],
  home: string,
): Promise<{ actions: DeployAction[]; warnings: PlanWarning[] }> {
  const resolvedSourceDir = path.resolve(sourceDir);
  let realRoot: string;
  try {
    realRoot = await realpath(resolvedSourceDir);
  } catch {
    realRoot = resolvedSourceDir;
  }

  const actions: DeployAction[] = [
    ...(await planSkillDirActions(
      manifest,
      sourceDir,
      resolvedSourceDir,
      realRoot,
      detectedAgents,
      home,
    )),
    ...(await planFileWriteActions(
      manifest,
      sourceDir,
      resolvedSourceDir,
      realRoot,
      detectedAgents,
      home,
    )),
    ...planConfigPatchActions(manifest, detectedAgents, home),
  ];

  const adapterResult = await compileAdapterActions(
    manifest.mcpServers,
    manifest.agentRules,
    sourceDir,
    resolvedSourceDir,
    realRoot,
    detectedAgents,
    home,
  );
  actions.push(...adapterResult.actions);

  const warnings: PlanWarning[] = [
    ...detectAmbiguities(detectedAgents, manifest),
    ...detectCollisions(actions),
    ...adapterResult.warnings,
  ];

