      stdout.includes("inception-engine"),
      "stdout should include tool name",
    );
    assert.ok(stdout.includes("--dry-run"), "stdout should include options");
  });

  it("no args exits 0 and prints usage", async () => {
    const { stdout, code } = await run([]);
    assert.equal(code, 0);
    assert.ok(
