import { lstat, readFile, realpath, stat } from "node:fs/promises";
import path from "node:path";
import { UserError } from "../errors.ts";

export function sourceAccessError(err: unknown, sourcePath: string): string {
  const code = (err as NodeJS.ErrnoException).code;
  if (code === "ENOENT") return `Source not found: ${sourcePath}`;
  if (code === "EACCES" || code === "EPERM")
    return `Permission denied accessing source: ${sourcePath}`;
  const detail = err instanceof Error ? err.message : String(err);
  return `Failed to access source ${sourcePath}: ${detail}`;
}

function normalizePathForComparison(candidate: string): string {
  const normalized = path.normalize(candidate);
  return process.platform === "win32" ? normalized.toLowerCase() : normalized;
}

function isSameOrDescendantPath(candidate: string, root: string): boolean {
  const normalizedCandidate = normalizePathForComparison(candidate);
  const normalizedRoot = normalizePathForComparison(root);
  return (
    normalizedCandidate === normalizedRoot ||
    normalizedCandidate.startsWith(normalizedRoot + path.sep)
  );
}

async function isSameFileSystemLocation(
  a: string,
  b: string,
): Promise<boolean> {
  const [aStat, bStat] = await Promise.all([stat(a), stat(b)]);
  return aStat.dev === bStat.dev && aStat.ino === bStat.ino;
}

async function isWithinRootByIdentity(
  candidate: string,
  root: string,
): Promise<boolean> {
  let current = candidate;
  while (true) {
    if (await isSameFileSystemLocation(current, root)) return true;
    const parent = path.dirname(current);
    if (parent === current) return false;
    current = parent;
  }
}

export async function validateSourcePath(
  source: string,
  skillPath: string,
  resolvedSourceDir: string,
  realRoot: string,
): Promise<void> {
  if (!source.startsWith(resolvedSourceDir + path.sep)) {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill path "${skillPath}" resolves outside the repository root: ${source}`,
    );
  }

  try {
    const realSource = await realpath(source);
    if (
      !(
        isSameOrDescendantPath(realSource, realRoot) ||
        (await isWithinRootByIdentity(realSource, realRoot))
      )
    ) {
      throw new UserError(
        "DEPLOY_FAILED",
        `Skill path "${skillPath}" resolves outside the repository root via symlink: ${source} -> ${realSource}`,
      );
    }
  } catch (err) {
    if (err instanceof UserError) throw err;
    // Source doesn't exist yet — will be caught during execute
  }
}

export async function validateSourceFile(
  sourcePath: string,
  manifestPath: string,
): Promise<void> {
  let stat: Awaited<ReturnType<typeof lstat>>;
  try {
    stat = await lstat(sourcePath);
  } catch (err) {
    throw new UserError("DEPLOY_FAILED", sourceAccessError(err, manifestPath));
  }
  if (!stat.isFile()) {
    throw new UserError(
      "DEPLOY_FAILED",
      `Source is not a file: ${manifestPath}`,
    );
  }
}

function isRecordOfStrings(value: unknown): value is Record<string, string> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.values(value).every((entry) => typeof entry === "string")
  );
}

function validateNonEmptyStringField(
  value: unknown,
  field: string,
  entryName: string,
  agentId: string,
): void {
  if (typeof value !== "string" || value.trim().length === 0) {
    throw new UserError(
      "DEPLOY_FAILED",
      `mcpServers entry "${entryName}" for agent "${agentId}" must define "${field}" as a non-empty string`,
    );
  }
}

export function validateMcpServerConfigShape(
  config: Record<string, unknown>,
  entryName: string,
  agentId: string,
): void {
  const hasCommand = Object.hasOwn(config, "command");
  const hasUrl = Object.hasOwn(config, "url");

  if (!(hasCommand || hasUrl)) {
    throw new UserError(
      "DEPLOY_FAILED",
      `mcpServers entry "${entryName}" for agent "${agentId}" must define either a non-empty "command" or "url"`,
    );
  }

  if (hasCommand) {
    validateNonEmptyStringField(config.command, "command", entryName, agentId);
  }
  if (hasUrl) {
    validateNonEmptyStringField(config.url, "url", entryName, agentId);
  }

  if (
    Object.hasOwn(config, "args") &&
    (!Array.isArray(config.args) ||
      config.args.some((arg) => typeof arg !== "string"))
  ) {
    throw new UserError(
      "DEPLOY_FAILED",
      `mcpServers entry "${entryName}" for agent "${agentId}" must define "args" as an array of strings when present`,
    );
  }

  if (Object.hasOwn(config, "env") && !isRecordOfStrings(config.env)) {
    throw new UserError(
      "DEPLOY_FAILED",
      `mcpServers entry "${entryName}" for agent "${agentId}" must define "env" as an object of string values when present`,
    );
  }
}

export function validateAgentRuleMarkdownPath(
  manifestPath: string,
  agentId: string,
): void {
  const extension = path.extname(manifestPath).toLowerCase();
  if (extension !== ".md" && extension !== ".markdown") {
    throw new UserError(
      "DEPLOY_FAILED",
      `agentRules entry "${manifestPath}" for agent "${agentId}" must point to a Markdown source file`,
    );
  }
}

function trimMatchingQuotes(value: string): string {
  if (
    (value.startsWith('"') && value.endsWith('"')) ||
    (value.startsWith("'") && value.endsWith("'"))
  ) {
    return value.slice(1, -1).trim();
  }
  return value;
}

function parseSimpleFrontmatterValue(
  field: string,
  rawValue: string,
  manifestPath: string,
): string {
  const value = trimMatchingQuotes(rawValue.trim());
  if (value.length === 0) {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill "${manifestPath}" SKILL.md frontmatter field "${field}" must be a non-empty string`,
    );
  }
  if (rawValue.trim() === "|" || rawValue.trim() === ">") {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill "${manifestPath}" SKILL.md frontmatter field "${field}" must be a single-line string`,
    );
  }
  return value;
}

export async function validateSkillDefinitionFile(
  sourcePath: string,
  manifestPath: string,
): Promise<void> {
  await validateSourceFile(sourcePath, `${manifestPath}/SKILL.md`);

  let raw: string;
  try {
    raw = await readFile(sourcePath, "utf-8");
  } catch (err) {
    throw new UserError(
      "DEPLOY_FAILED",
      sourceAccessError(err, `${manifestPath}/SKILL.md`),
    );
  }

  const lines = raw.split(/\r?\n/);
  if (lines[0]?.trim() !== "---") {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill "${manifestPath}" SKILL.md must start with YAML frontmatter delimited by ---`,
    );
  }

  const closingIndex = lines.findIndex(
    (line, index) => index > 0 && line.trim() === "---",
  );
  if (closingIndex === -1) {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill "${manifestPath}" SKILL.md is missing the closing --- frontmatter delimiter`,
    );
  }

  let name: string | null = null;
  let description: string | null = null;
  for (const line of lines.slice(1, closingIndex)) {
    const trimmed = line.trim();
    if (trimmed.length === 0 || trimmed.startsWith("#")) continue;

    const match = /^([A-Za-z0-9_-]+)\s*:\s*(.*)$/.exec(line);
    if (!match) continue;

    const [, key, rawValue] = match;
    if (key === "name") {
      name = parseSimpleFrontmatterValue("name", rawValue, manifestPath);
    } else if (key === "description") {
      description = parseSimpleFrontmatterValue(
        "description",
        rawValue,
        manifestPath,
      );
    }
  }

  }

  if (name === null) {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill "${manifestPath}" SKILL.md frontmatter must include a non-empty "name" field`,
    );
  }
  if (description === null) {
    throw new UserError(
      "DEPLOY_FAILED",
      `Skill "${manifestPath}" SKILL.md frontmatter must include a non-empty "description" field`,
    );
  }
}

import assert from "node:assert/strict";
import fs from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, it } from "node:test";
import {
  applyTomlMcpPatch,
  revertTomlMcpPatch,
} from "../../src/core/adapters/toml.ts";

describe("TOML Adapter", () => {
  let tmpDir: string;

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), "inception-toml-test-"));
  });

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  it("applies an MCP server patch to a new TOML file", async () => {
    const target = path.join(tmpDir, "config.toml");
    const config = { command: "npx", args: ["serve"] };

    await applyTomlMcpPatch(target, "my-skill", config);

    const content = await fs.readFile(target, "utf-8");
    assert.match(content, /\[mcpServers\.my-skill\]/);
    assert.match(content, /command = "npx"/);
    assert.match(content, /args = \[ "serve" \]/);
  });

  it("applies an MCP server patch to an existing TOML file preserving other keys", async () => {
    const target = path.join(tmpDir, "config.toml");
    await fs.writeFile(
      target,
      'title = "My App"\n\n[mcpServers.other]\ncommand = "ls"\n',
    );

    const config = { command: "npx", args: ["serve"] };
    await applyTomlMcpPatch(target, "my-skill", config);

    const content = await fs.readFile(target, "utf-8");
    assert.match(content, /title = "My App"/);
    assert.match(content, /\[mcpServers\.other\]/);
    assert.match(content, /\[mcpServers\.my-skill\]/);
    assert.match(content, /command = "npx"/);
  });

  it("reverts an MCP server patch", async () => {
    const target = path.join(tmpDir, "config.toml");
    await fs.writeFile(
      target,
      '[mcpServers.other]\ncommand = "ls"\n\n[mcpServers.my-skill]\ncommand = "npx"\n',
    );

    await revertTomlMcpPatch(target, "my-skill");

    const content = await fs.readFile(target, "utf-8");
    assert.match(content, /\[mcpServers\.other\]/);
    assert.doesNotMatch(content, /my-skill/);
  });

  it("cleans up [mcpServers] table if it becomes empty after revert", async () => {
    const target = path.join(tmpDir, "config.toml");
    await fs.writeFile(target, '[mcpServers.my-skill]\ncommand = "npx"\n');

    await revertTomlMcpPatch(target, "my-skill");

    const content = await fs.readFile(target, "utf-8");
    assert.strictEqual(content.trim(), "");
  });

  it("throws error if config.toml is invalid TOML", async () => {
    const target = path.join(tmpDir, "config.toml");
    await fs.writeFile(target, 'this is not = toml "bad"');

    await assert.rejects(
      () => applyTomlMcpPatch(target, "any", {}),
      /Invalid TOML document/,
    );
  });
});

